class Main {
  // Version 1: Two ints
  static int add(int a, int b) {
    return a + b;
  }

  // Version 2: Three ints
  static int add(int a, int b, int c) {
    return a + b + c;
  }

  // Version 3: Two doubles
  static double add(double a, double b) {
    return a + b;
  }

  public static void main(String[] args) {
    System.out.println(add(2, 3));       // Calls V1
    System.out.println(add(1, 2, 3));    // Calls V2
    System.out.println(add(1.5, 2.5));   // Calls V3
  }
}
